(async()=>{
  const sleep=ms=>new Promise(r=>setTimeout(r,ms));
  const visible=el=>{if(!el)return false;const s=getComputedStyle(el),r=el.getBoundingClientRect();return s.display!=='none'&&s.visibility!=='hidden'&&parseFloat(s.opacity||'1')>0&&r.width>0&&r.height>0;};
  const txt=el=>(el.innerText||el.textContent||'').replace(/\s+/g,' ').trim();
  const state=()=>{
    const text=[document.body.innerText,[...document.querySelectorAll('svg text,text')].map(e=>e.textContent).join(' ')].join(' ').replace(/\s+/g,' ');
    const rects=[...document.querySelectorAll('svg rect,rect,[class*=bar]')].filter(visible).map(r=>({fill:(r.getAttribute('fill')||getComputedStyle(r).fill||getComputedStyle(r).backgroundColor||'').toLowerCase(),op:getComputedStyle(r).opacity,display:getComputedStyle(r).display,h:r.getBoundingClientRect().height,y:r.getBoundingClientRect().y}));
    return {text,rects,senior:rects.filter(r=>/(#8b5cf6|purple|rgb\(139, 92, 246\))/.test(r.fill)&&r.display!=='none'&&parseFloat(r.op||'1')>0&&r.h>0).length,hash:rects.map(r=>r.fill+':'+Math.round(r.h)+':'+Math.round(r.y)+':'+r.op).join('|')};
  };
  const before=state();
  const controls=[...document.querySelectorAll('button,[role=button],a,label,li,div,span')].filter(visible).filter(el=>/senior/i.test(txt(el)||el.getAttribute('aria-label')||''));
  if(!controls.length) return false;
  controls.sort((a,b)=>(txt(a).length||99)-(txt(b).length||99))[0].click();
  await sleep(700);
  const after=state();
  const totalsBefore=['43','17','21','28','10'].filter(v=>new RegExp('(^|\\D)'+v+'(\\D|$)').test(before.text)).length;
  const totalsAfter=['35','14','17','23','8'].filter(v=>new RegExp('(^|\\D)'+v+'(\\D|$)').test(after.text)).length;
  const seniorReduced=after.senior<before.senior;
  const geometryChanged=after.hash!==before.hash;
  return before.senior>=5&&(seniorReduced||geometryChanged)&&totalsBefore>=3&&(totalsAfter>=3||after.text!==before.text);
})()

